// Webhook GET params land directly on the json object

const data =$input.first().json.query ;
return {
  json: {
    // --- DISCOUNT ---
    discount_type:     data.discount_type    ?? null,  // "percentage" | "fixed"
    percentage_value:  data.percentage_value  ?? null,  // filled if percentage chosen
    fixed_value:       data.fixed_value      ?? null,  // filled if fixed chosen

    // --- COUNTRY ---
    country:           data.country          ?? null,
    purchase_price:    data.Purchase_price    ?? null, 
    product_stock :    data.Product_stock     ?? null,
    product_name :     data.Product_Name      ?? null,
    commercial_model : data.the_commercial_model_code ?? null,

    // --- TRIGGER ---
    trigger_type:      data.trigger_type     ?? null,  // "order_amount" | "customer_type"
    order_amount:      data.order_amount     ?? null,  // filled if order_amount chosen
    customer_type:     data.customer_type    ?? null,  // "vip" | "new_user"
  }
};

// Input from AI agent
const input =$('AI Agent').first().json.output ;

// ─── 1. Clean & split into raw sections ───────────────────────────────────────
const sections = input
  .split(/---\s+/)          // split on "--- " (with optional spaces)
  .map(s => s.trim())
  .filter(Boolean);         // remove empty chunks

// ─── 2. Parse each section into { title, body } ───────────────────────────────
const parsed = sections.map(section => {
  const newlineIndex = section.indexOf('\\n');          // first line break
  const title = section.slice(0, newlineIndex !== -1 ? newlineIndex : undefined).trim();
  const body  = newlineIndex !== -1
    ? section.slice(newlineIndex).replace(/\\n/g, ' ').trim()
    : '';

  return { title, body };
});

// ─── 3. Build a structured output object (keys derived from titles) ────────────
const structured = {};

parsed.forEach(({ title, body }) => {
  // Convert title to a camelCase key  e.g. "Discount Plan" → "discountPlan"
  const key = title
    .toLowerCase()
    .replace(/[^a-z0-9 ]/g, '')          // strip special chars
    .trim()
    .replace(/\s+(.)/g, (_, c) => c.toUpperCase()); // camelCase

  structured[key] = {
    title,
    body,
    // ── bonus: extract any percentages found in the body
    percentages: [...body.matchAll(/(\d+(?:\.\d+)?)\s*%/g)].map(m => parseFloat(m[1])),
    // ── bonus: extract any large numbers (e.g. stock units)
    numbers: [...body.matchAll(/\b(\d{4,})\b/g)].map(m => parseInt(m[1])),
    // ── bonus: extract country mentions (capitalised proper nouns after "in")
    locations: [...body.matchAll(/\bin\s+([A-Z][a-z]+)/g)].map(m => m[1]),
  };
});

// ─── 4. Final output ──────────────────────────────────────────────────────────
return [{ json: { sections: parsed, structured } }];

// ============================================================
// n8n Code Node — Output Validator
// Input: $input.first().json.output
// Stock: $input.first().json.product_stock (or via node expression)
// ============================================================

const output = $input.first().json.output;
const stock  = $('Edit Fields').first().json.query.Product_stock; // e.g. "high" | "moderate" | "low" | null

// ── helpers ─────────────────────────────────────────────────
const errors   = [];
const warnings = [];

function fail(rule, msg) { errors.push({ rule, message: msg }); }
function warn(rule, msg) { warnings.push({ rule, message: msg }); }

// ── 0. null / type guard ─────────────────────────────────────
if (output === null || output === undefined || typeof output !== "string" || output.trim() === "") {
  return [{
    json: {
      valid: false,
      errors: [{ rule: "INPUT_NULL", message: "output is null, undefined, or empty." }],
      warnings: [],
      summary: "❌ Validation failed — output is missing."
    }
  }];
}

const text = output.trim();

// ============================================================
// CHECK 1 — Output Structure (section headers & order)
// ============================================================
const SECTION_REGEX  = /^---\s+(.+)$/gm;
const PLAN_HEADER    = /^---\s+Discount Plan\s*$/m;
const WHY_HEADER     = /^---\s+Why This Plan\s*$/m;

const allSections = [...text.matchAll(SECTION_REGEX)];

if (allSections.length !== 2) {
  fail("STRUCTURE", `Expected exactly 2 sections (--- headers), found ${allSections.length}.`);
}
if (!PLAN_HEADER.test(text)) {
  fail("STRUCTURE", 'Missing or malformed header "--- Discount Plan".');
}
if (!WHY_HEADER.test(text)) {
  fail("STRUCTURE", 'Missing or malformed header "--- Why This Plan".');
}

// Order check
const planIdx = text.search(PLAN_HEADER);
const whyIdx  = text.search(WHY_HEADER);
if (planIdx !== -1 && whyIdx !== -1 && planIdx >= whyIdx) {
  fail("STRUCTURE", '"--- Discount Plan" must appear before "--- Why This Plan".');
}

// ============================================================
// CHECK 2 — No Forbidden Formats
// ============================================================
const forbiddenPatterns = [
  { pattern: /\n\s*[-*]\s+/,        label: "bullet points (- or *)" },
  { pattern: /\n\s*\d+\.\s+/,       label: "numbered list (1. 2. …)" },
  { pattern: /\|/,                   label: "table separator (|)" },
];
for (const { pattern, label } of forbiddenPatterns) {
  if (pattern.test(text)) {
    fail("FORBIDDEN_FORMAT", `Output contains forbidden formatting: ${label}.`);
  }
}

// ============================================================
// CHECK 3 — Paragraph-only format (no excessive blank lines)
// ============================================================
// Split into sections first, then check inside each section body
const sectionBodies = getSectionBodies(text);

for (const [title, body] of Object.entries(sectionBodies)) {
  // More than 2 consecutive newlines = fragmented/list-like
  if (/\n{3,}/.test(body)) {
    fail("PARAGRAPH_FORMAT", `Section "${title}" contains excessive blank lines (fragmented text).`);
  }
}

// ============================================================
// CHECK 4 — Null field suppression
// ============================================================
// Collect null fields from input JSON
const inputJson = $input.first().json;
const nullFields = Object.entries(inputJson)
  .filter(([, v]) => v === null)
  .map(([k]) => k.toLowerCase());

// Map field names to likely keywords that would appear in output
const nullKeywordMap = {
  country:               ["country", "region", "market", "territory"],
  product_stock:         ["stock level", "inventory", "stock"],
  discount_type:         [],  // always required — skip null check
  trigger_target:        ["trigger", "vip", "minimum order", "new client", "bad feedback"],
  discount_value:        [],
  // extend as needed
};

for (const field of nullFields) {
  const keywords = nullKeywordMap[field] ?? [field.replace(/_/g, " ")];
  for (const kw of keywords) {
    const regex = new RegExp(`\\b${escapeRegex(kw)}\\b`, "i");
    if (regex.test(text)) {
      fail("NULL_FIELD_LEAK", `Field "${field}" is null but its keyword "${kw}" appears in the output.`);
    }
  }
}

// ============================================================
// CHECK 5 — Key elements inside "Discount Plan"
// ============================================================
const planBody = sectionBodies["Discount Plan"] ?? "";

// Discount type keyword
if (!/\bpercentage\b|\bfixed\b|\bbundle\b|\bdynamic\b/i.test(planBody)) {
  fail("KEY_ELEMENTS", '"Discount Plan" does not mention a discount type (percentage / fixed / bundle / dynamic).');
}

// At least one number (covers values like 10%, $50, 15 USD)
if (!/\d+/.test(planBody)) {
  fail("KEY_ELEMENTS", '"Discount Plan" contains no numeric values (base or final discount value missing).');
}

// Trigger condition keyword
const triggerKeywords = [
  "vip", "new client", "minimum order", "bad feedback",
  "loyalty", "threshold", "clearance", "overstock", "campaign"
];
const hasTrigger = triggerKeywords.some(kw =>
  new RegExp(`\\b${escapeRegex(kw)}\\b`, "i").test(planBody)
);
if (!hasTrigger) {
  warn("KEY_ELEMENTS", '"Discount Plan" has no detectable trigger condition keyword (VIP, minimum order, clearance, etc.).');
}

// ============================================================
// CHECK 6 — Value Adjustment Logic (stock heuristic)
// ============================================================
const STOCK_LOW      = 50;
const STOCK_HIGH     = 200;

if (stock !== null && stock !== undefined) {
  const stockNum = Number(stock);

  if (isNaN(stockNum)) {
    fail("VALUE_LOGIC", `product_stock must be a number, got: "${stock}".`);
  } else {
    const numbers = extractNumbers(planBody);

    if (numbers.length >= 2) {
      const base  = numbers[0];
      const final = numbers[numbers.length - 1];

      if (stockNum > STOCK_HIGH && final < base) {
        fail(
          "VALUE_LOGIC",
          `Stock is HIGH (${stockNum} > ${STOCK_HIGH}) — final discount value (${final}) should be ≥ base value (${base}), but it is lower.`
        );
      }

      if (stockNum < STOCK_LOW && final > base) {
        fail(
          "VALUE_LOGIC",
          `Stock is LOW (${stockNum} < ${STOCK_LOW}) — final discount value (${final}) should be ≤ base value (${base}), but it is higher.`
        );
      }

      // moderate: just log in meta, no hard rule
    } else {
      warn(
        "VALUE_LOGIC",
        "Could not extract at least 2 numbers from Discount Plan to compare base vs final value."
      );
    }
  }
}
// ============================================================
// CHECK 7 — Section Length Constraints
// ============================================================
const whyBody = sectionBodies["Why This Plan"] ?? "";

const planSentences = countSentences(planBody);
const whySentences  = countSentences(whyBody);

if (planSentences < 1) {
  fail("SECTION_LENGTH", '"Discount Plan" must contain at least 1 sentence.');
}
if (whySentences < 2) {
  fail("SECTION_LENGTH", `"Why This Plan" must have at least 2 sentences (found ${whySentences}).`);
}
if (whySentences > 4) {
  fail("SECTION_LENGTH", `"Why This Plan" must have at most 4 sentences (found ${whySentences}).`);
}

// ============================================================
// CHECK 8 — No Extra Sections
// ============================================================
// Already covered by Check 1 (allSections.length !== 2), but be explicit:
if (allSections.length > 2) {
  fail("EXTRA_SECTIONS", `Only 2 sections allowed. Found extra section(s): ${allSections.slice(2).map(m => m[1]).join(", ")}.`);
}

// ============================================================
// CHECK 9 — Tone / Style (blacklist)
// ============================================================
const casualPhrases = [
  "hey", /\byou should\b/i, /\bmaybe\b/i, /\byou could\b/i,
  /\bconsider\b/i, /\bperhaps\b/i, /\bwhy not\b/i, /\btry to\b/i
];

for (const phrase of casualPhrases) {
  const regex = phrase instanceof RegExp ? phrase : new RegExp(`\\b${escapeRegex(phrase)}\\b`, "i");
  if (regex.test(text)) {
    const label = phrase instanceof RegExp ? phrase.source : phrase;
    fail("TONE", `Output contains informal/suggestive language: "${label}".`);
  }
}

// ============================================================
// ── utility functions ────────────────────────────────────────
// ============================================================

function getSectionBodies(str) {
  const result = {};
  const matches = [...str.matchAll(/^---\s+(.+)$/gm)];
  for (let i = 0; i < matches.length; i++) {
    const title = matches[i][1].trim();
    const start = matches[i].index + matches[i][0].length;
    const end   = i + 1 < matches.length ? matches[i + 1].index : str.length;
    result[title] = str.slice(start, end).trim();
  }
  return result;
}

function countSentences(str) {
  if (!str) return 0;
  // Split on . ! ? followed by space or end, ignore abbreviations heuristically
  const parts = str.split(/(?<=[.!?])\s+(?=[A-Z"'])/);
  return parts.filter(s => s.trim().length > 4).length;
}

function extractNumbers(str) {
  const matches = str.match(/\d+(?:\.\d+)?/g);
  return matches ? matches.map(Number) : [];
}

function escapeRegex(s) {
  return s.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
}

// ============================================================
// ── Final Output ─────────────────────────────────────────────
// ============================================================

const valid = errors.length === 0;

return [{
  json: {
    valid,
    summary: valid
      ? `✅ Validation passed${warnings.length ? ` (${warnings.length} warning(s))` : ""}.`
      : ` Validation failed — ${errors.length} error(s) found.`,
    errors,
    warnings,
    meta: {
      sections_found:    allSections.length,
      plan_sentences:    countSentences(sectionBodies["Discount Plan"] ?? ""),
      why_sentences:     countSentences(sectionBodies["Why This Plan"] ?? ""),
      stock_input:       stock ?? null,
      null_fields_found: nullFields,
    }
  }
}];

